function getValue(tree: TranslationTree, path: string) {
  if (typeof path !== 'string' || !path.trim()) {
    return undefined;
  }

  return path.split('.').reduce<unknown>((current, segment) => {
    if (!segment || blockedPathSegments.has(segment) || !isPlainObject(current)) {
      return undefined;
    }

    if (!Object.prototype.hasOwnProperty.call(current, segment)) {
      return undefined;
    }

    return current[segment];
  }, tree);
}

function resolveTranslation(locale: Locale, key: string) {
  const value = getValue(translationsWithFallback[locale], key);
  return typeof value === 'string' ? value : undefined;
}

function interpolate(value: string, params?: Params) {
  if (!params) {
    return value;
  }

  return value.replace(/\{\{(\w+)\}\}/g, (_, key: string) => String(params[key] ?? ''));
}

export function useI18n() {
  const { language, setLanguage, currency } = useAppState();

  const currentLanguage: Locale = language === 'system' ? 'pt-BR' : isLocale(language) ? language : 'pt-BR';

  return useMemo(
    () => ({
      language: currentLanguage,
      currencyLabel: currency,
      setLanguage,
      t: (key: string, params?: Params) => {
        const value = resolveTranslation(currentLanguage, key) ?? resolveTranslation('pt-BR', key);
        return typeof value === 'string' ? interpolate(value, params) : key;
      },
    }),
    [currency, currentLanguage, setLanguage],
  );
}
